import{_ as d,o as n,c as o,ag as r}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"时间复杂度与空间复杂度分析","description":"","frontmatter":{"title":"时间复杂度与空间复杂度分析","difficulty":"easy","tags":["复杂度分析","大O记号","algorithm-basics"],"estimate":15},"headers":[],"relativePath":"domains/algorithms/qa/qa-01-complexity-analysis.md","filePath":"domains/algorithms/qa/qa-01-complexity-analysis.md","lastUpdated":1783504823000}'),a={name:"domains/algorithms/qa/qa-01-complexity-analysis.md"};function l(e,t,s,i,g,h){return n(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="问答-01-入门-时间复杂度与空间复杂度分析" tabindex="-1">问答 01（入门）：时间复杂度与空间复杂度分析 <a class="header-anchor" href="#问答-01-入门-时间复杂度与空间复杂度分析" aria-label="Permalink to &quot;问答 01（入门）：时间复杂度与空间复杂度分析&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>什么是时间复杂度和空间复杂度？大 O 记号（Big-O）表示什么？请给出常见排序、查找、树、图算法的复杂度速查，并说明「摊还复杂度」和「平均复杂度」的区别。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>基本概念</strong></p><ul><li><strong>时间复杂度</strong>：算法执行需要的<strong>基本操作次数</strong>随输入规模 n 的增长趋势。</li><li><strong>空间复杂度</strong>：算法运行过程中<strong>额外占用的存储空间</strong>随 n 的增长趋势（不含输入本身）。</li><li>二者都是关心「量级」，不关心常数因子和低阶项。</li></ul><p><strong>大 O 记号</strong></p><ul><li><strong>O(f(n))</strong>：上界，即最坏情况下不会超过 f(n) 的某个常数倍。</li><li><strong>Ω(f(n))</strong>：下界。</li><li><strong>Θ(f(n))</strong>：紧确界（上下界一致）。</li><li>面试和工程中一般说的「复杂度」默认是 O（最坏或期望）。</li></ul><p><strong>复杂度阶次从小到大</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>O(1) &lt; O(log n) &lt; O(√n) &lt; O(n) &lt; O(n log n) &lt; O(n²) &lt; O(n³) &lt; O(2ⁿ) &lt; O(n!) &lt; O(nⁿ)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>常见算法复杂度速查</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>算法</th><th>平均时间</th><th>最坏时间</th><th>空间</th><th>稳定</th></tr></thead><tbody><tr><td>排序</td><td>冒泡 / 选择 / 插入</td><td>O(n²)</td><td>O(n²)</td><td>O(1)</td><td>冒/插 稳定</td></tr><tr><td>排序</td><td>归并</td><td>O(n log n)</td><td>O(n log n)</td><td>O(n)</td><td>稳定</td></tr><tr><td>排序</td><td>快排</td><td>O(n log n)</td><td>O(n²)</td><td>O(log n)</td><td>不稳定</td></tr><tr><td>排序</td><td>堆排</td><td>O(n log n)</td><td>O(n log n)</td><td>O(1)</td><td>不稳定</td></tr><tr><td>排序</td><td>计数 / 基数 / 桶</td><td>O(n+k)</td><td>O(n+k)</td><td>O(n+k)</td><td>稳定</td></tr><tr><td>查找</td><td>线性查找</td><td>O(n)</td><td>O(n)</td><td>O(1)</td><td>—</td></tr><tr><td>查找</td><td>二分查找（有序）</td><td>O(log n)</td><td>O(log n)</td><td>O(1)</td><td>—</td></tr><tr><td>查找</td><td>哈希表（均摊）</td><td>O(1)</td><td>O(n)</td><td>O(n)</td><td>—</td></tr><tr><td>树</td><td>BST 查找/插入</td><td>O(log n)</td><td>O(n)</td><td>O(log n)</td><td>—</td></tr><tr><td>树</td><td>平衡 BST（AVL/红黑）</td><td>O(log n)</td><td>O(log n)</td><td>O(log n)</td><td>—</td></tr><tr><td>图</td><td>BFS / DFS</td><td>O(V+E)</td><td>O(V+E)</td><td>O(V)</td><td>—</td></tr><tr><td>图</td><td>Dijkstra（堆优化）</td><td>O((V+E) log V)</td><td>—</td><td>O(V)</td><td>—</td></tr></tbody></table><p><strong>摊还 vs 平均</strong></p><ul><li><strong>摊还复杂度（amortized）</strong>：单次操作可能很慢，但<strong>多次操作总代价除以次数</strong>是一个较低的量级。经典例子：动态数组 push（偶尔扩容 O(n)，但均摊 O(1)）；哈希表插入。</li><li><strong>平均复杂度（average-case）</strong>：对<strong>输入的概率分布</strong>求期望。经典例子：快排平均 O(n log n)（假设输入随机）。</li><li>区别：摊还是<strong>同一算法多次操作的总代价分摊</strong>，与输入分布无关；平均是<strong>对输入分布求期望</strong>。</li></ul><p><strong>分析技巧</strong></p><ul><li>循环嵌套：每层循环的次数相乘。</li><li>递归：写出递推式，用主定理（Master Theorem）或递归树分析。例如 <code>T(n) = 2T(n/2) + O(n)</code> → O(n log n)。</li><li>忽略常数与低阶项：<code>O(3n² + 5n + 10) = O(n²)</code>。</li><li>空间要单独看：不要把「输入本身」算进去，通常只算辅助空间。</li></ul><h2 id="追问-1-o-log-n-里的-log-底数是几-为什么可以省略" tabindex="-1">追问 1：<code>O(log n)</code> 里的 log 底数是几？为什么可以省略？ <a class="header-anchor" href="#追问-1-o-log-n-里的-log-底数是几-为什么可以省略" aria-label="Permalink to &quot;追问 1：`O(log n)` 里的 log 底数是几？为什么可以省略？&quot;">​</a></h2><p><strong>答</strong>：底数可以是任意大于 1 的常数（2、e、10 都行）。因为 <code>log_a(n) = log_b(n) / log_b(a)</code>，不同底数只差一个常数因子，而大 O 忽略常数，所以写 <code>O(log n)</code> 不带底数。工程中习惯默认底数为 2（二分/树结构）。</p><h2 id="追问-2-递归函数的空间复杂度包含什么-为什么尾递归可以省空间" tabindex="-1">追问 2：递归函数的空间复杂度包含什么？为什么尾递归可以省空间？ <a class="header-anchor" href="#追问-2-递归函数的空间复杂度包含什么-为什么尾递归可以省空间" aria-label="Permalink to &quot;追问 2：递归函数的空间复杂度包含什么？为什么尾递归可以省空间？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>递归的空间主要是<strong>调用栈</strong>：每次递归调用都会在栈上压入一帧（保存局部变量、返回地址、参数），最大栈深度就是空间复杂度的主项。</li><li>例：普通递归求阶乘 <code>f(n) = n * f(n-1)</code> 栈深 n，空间 O(n)。</li><li><strong>尾递归</strong>是指递归调用是函数返回前的<strong>最后一个动作</strong>，无需保留当前栈帧。支持尾调用优化（TCO）的语言/编译器会复用栈帧，让空间降到 O(1)。JS 引擎（除 Safari 部分场景）当前<strong>不做 TCO</strong>，所以写尾递归在 JS 里实际不省空间，仍要注意栈溢出，改写成迭代更稳妥。</li></ul><h2 id="追问-3-array-prototype-push-为什么说是-o-1-均摊-如何证明" tabindex="-1">追问 3：<code>Array.prototype.push</code> 为什么说是 O(1) 均摊？如何证明？ <a class="header-anchor" href="#追问-3-array-prototype-push-为什么说是-o-1-均摊-如何证明" aria-label="Permalink to &quot;追问 3：`Array.prototype.push` 为什么说是 O(1) 均摊？如何证明？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>V8 底层用<strong>动态数组</strong>实现，当容量不够时会新分配一块更大（通常 1.5x～2x）的内存，再把旧元素拷贝过去（O(n)）。</li><li>单次扩容看是 O(n)，但<strong>扩容频率随 n 指数级减少</strong>。假设扩容因子 2，第 n 次 push 时前面总扩容代价约 <code>1 + 2 + 4 + ... + n = 2n - 1</code>，均摊到每次 push 是 O(1)。</li><li>用<strong>聚合分析</strong>或<strong>记账法</strong>都可证明：给每次 push 分配 3 个「代币」（1 个用于本次，2 个存起来），扩容时用存下来的代币付拷贝费用，收支平衡，因此均摊 O(1)。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/algorithms/RESOURCES">算法 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://mitpress.mit.edu/9780262046305/introduction-to-algorithms/" target="_blank" rel="noreferrer">CLRS (Introduction to Algorithms)</a>：大 O 记号、主定理与摊还分析的严格定义与证明</li><li><a href="https://www.bigocheatsheet.com/" target="_blank" rel="noreferrer">Big-O Cheat Sheet</a>：常见数据结构与算法的时间/空间复杂度速查</li><li><a href="https://oi-wiki.org/basic/complexity/" target="_blank" rel="noreferrer">OI Wiki: 复杂度</a>：中文入门，覆盖最坏/平均/摊还复杂度与主定理</li></ul>',27)])])}const c=d(a,[["render",l]]);export{p as __pageData,c as default};
